#include<bits/stdc++.h>using namespace std;int main(){    int t;cin>>t;    while (t--)    {        int n;cin>>n;        vector<long long> v(n),pref(n+1);        pref[0]=0;        for(int i=1;i<=n;++i) {            cin>>v[i-1];            pref[i]=pref[i-1]+v[i-1];        }        long long mx=1;        for(int i=1;i<n;++i){            mx=max(mx,__gcd(pref[i],pref[n]-pref[i]));        }        cout<<mx<<endl;    }    }